import { Enum, Vec3, color, v3 } from "cc";
import { newBottombarManager } from "db://astarte-framework/Managers";

enum GAMEVIEW_STATE
{
    WAIT_READY,
    PLATE_SHOW,
    FEATURE_SHOW,
    UNSHOW_PREPARE,
    AWARD,
    ROUND_SHOW_END,
    ROUND_END,

    EFFECT_START,
    // CHECK_JP,
    SCATTER_SHOW,
    ENTER_FREE,
    FULL_REWARD,
    LEAVE_FREE,
    ADD_FREE,
    //TODO
    ENTER_BONUS,
    BONUS_GAME,
    LEAVE_BONUS,
}

export enum Symbol
{
    /**@ch WILD*/
    Wild = 0,

    /**@ch 羅賓漢*/
    RobinHood,

    /**@ch 小約翰*/
    LittleJohn,

    /**@ch 塔克*/
    Tucker,

    /**@ch 士兵*/
    Soldier,

    A,

    K,

    Q,

    J,

    Ten,

    /**@ch 黃金箭*/
    GoldenArrow = 10,

    /**@ch 散射(號角)*/
    Scatter,

    /**@ch 羅賓漢 WILD*/
    WildRobinHood,

    /**@ch 小約翰 WILD*/
    WildLittleJohn,

    /**@ch 塔克 WILD*/
    WildTucker,

    /**Empty*/
    MAX = 15,
}

export enum AddEffectPrefabs
{
    /**中獎框*/
    FX_FRAME,
    /**金幣特效*/
    SCATTER_FX
}

export class SymbolInfo
{
    /**@ch 符號ID*/
    Symbol: number;

    /**@ch 符號值*/
    Value: number;

    /**@ch JP類型*/
    JpType: number;
}

export enum FeverGameType
{
    /**@ch 一般遊戲*/
    MainGame = 0,

    /**@ch Free Game*/
    FreeGame = 1,

    /**@ch Bonus Game*/
    BonusGame = 2,
}

/**@ch 特殊功能位置佇列*/
export enum FeaturePosQueueType
{
    /**@ch Scatter 出現位置*/
    Scatter = 0,

    /**@ch 黃金箭 出現位置*/
    GoldenArrow = 1,
}

export enum GAME_EVENT {
    DEVICE_ROTATION = "GAME_EVENT_DEVICE_ROTATION",
    CHANGE_BET = "GAME_EVENT_CHANGE_BET",
}

export enum AwardUIEventName
{
    SHOW_BLACK_MASK = "SHOW_BLACK_MASK",
    HIDE_BLACK_MASK = "HIDE_BLACK_MASK",

    /**
     * @ch 顯示透明黑遮罩
     * @param (選填) touch callback 點擊遮罩的 callback
     * */
    SHOW_TRANSPARENT_BLACK_MASK = "SHOW_TRANSPARENT_BLACK_MASK",

    /**
     * @ch 隱藏透明黑遮罩
     * */
    HIDE_TRANSPARENT_BLACK_MASK = "HIDE_TRANSPARENT_BLACK_MASK",
}

/// <summary> 贏分類型 </summary>
export enum WinType {
    NoWin,

    /** 0 < 倍率 < 5 */
    NormalWin,

    /** 5 <= 倍率 < 10 */
    YouWin,

    /** 10 <= 倍率 < 25 */
    BigWin,

    /** 25 <= 倍率 < 50 */
    MegaWin,

    /** 50 <= 倍率 */
    SuperWin,

    SpecialWin, //for 特殊遊戲回Lobby，不足10倍報獎
  }

export default class Game_Define
{
    static Ver: string = "Ver";
    static BgAudioId: number = -1;
    static SPICY_LEVEL = 2;
    static Symbol = Enum( Symbol );
    static GameState = Enum( GAMEVIEW_STATE );

    /**@ch For盤面壓黑 */
    static Color = {
        Light: color( 255, 255, 255 ),
        Dark: color( 101.25, 94.5, 73.5 ),
    };

    /**@ch 取得當前BET，會受extraBet影響 */
    static GetNowBetValue()
    {
        return newBottombarManager.GetNowBetValue();
    }

    /**@ch 是否需要為暗色符號黑幕 */
    static IsDarkSymbolBlackMask(symbol: number)
    {
        return symbol >= Symbol.A && symbol <= Symbol.Ten;
    }

    /************************** 多語系 **************************/
    static BUY_BONUS_TXT = [
        "Txt_Buy_Feature_Bet",
        "Txt_Buy_Feature_Title",
        "BuyBonus_IconName",
    ];

    static COL = 5;
    static ROW = 3;
    static MAX_ROW = 3; // 最大行數
    static FULL_PLATE_NUM = 15;
    static SeparateLineWidth = 6; // pixels
    static SCATTER_MAX_COUNT = 3;

    /**@ch Scatter 中獎動畫相關時間設定（秒） */
    static SCATTER_BINGO_INITIAL_WAIT_TIME = 1;      // Scatter 中獎初始等待時間
    static SCATTER_BINGO_AUDIO_WAIT_TIME = 2;        // Scatter 中獎音效播放後等待時間

    /**@ch Bingo Combo 音效範圍 */
    static BINGO_COMBO_MIN_COUNT = 1;  // 最小有效 Combo 計數
    static BINGO_COMBO_MAX_COUNT = 6;  // 最大 Combo 音效數量

    /**@ch 線配置 - 記錄每條線涉及的位置索引 (0-14)
     * 盤面位置索引:
     *  0    3    6    9   12
     *  1    4    7   10   13
     *  2    5    8   11   14
     */
    static Lines = [
        [1, 4, 7, 10, 13],  // Line 1
        [0, 3, 6, 9, 12],   // Line 2
        [2, 5, 8, 11, 14],  // Line 3
        [0, 4, 8, 10, 12],  // Line 4
        [2, 4, 6, 10, 14],  // Line 5
        [1, 3, 6, 9, 13],   // Line 6 
        [1, 5, 8, 11, 13],  // Line 7
        [0, 3, 7, 11, 14],  // Line 8
        [2, 5, 7, 9, 12],   // Line 9
        [1, 5, 7, 9, 13],   // Line 10
    ];

    /**@ch 獲取線位置陣列
     * @param lineIndex 線的索引 (0-9)
     * @returns 該線涉及的位置索引陣列
     */
    static GetLinePositions(lineIndex: number, count: number): number[] {
        if (lineIndex >= 0 && lineIndex < this.Lines.length) {
            return this.Lines[lineIndex].slice(0, count);
        }
        return [];
    }

    static SymbolHeight = 158;
    static SymbolWidth = 172;

    static IsFG: boolean = false;
    // static FullRound = 3;
    static CanScaleWinValue = true;

    static InitSize: Vec3 = v3( 0.1, 0.1 );
    static EndSize: Vec3 = v3( 1, 1 );

    /**@ch 表演輪(中)，實際轉輪 */
    static MIDDLE_PLATE_INDEX = 1;

    static NODE_PREFIX_NAME = [
        "low",
        "",
        "up"
    ];

    static THOUSAND = 1000;
    static MILLION = 1000000;

    /**@ch 飛行特效種類*/
    static FLY_TYPES = 4;

    /**@ch Effect表演分層數(4)，視各遊戲需求*/
    static EFFECT_LAYER_NUMS = 4;
    static LAYERS = {
        ONE: 0,
        TWO: 1,
        THREE: 2,
        FOUR: 3,
    };

    /**@ch 遊戲中須創造之表演大分類，(以此三幣瑞龍為例，symbol算一種、飛行特效算一種、盤面共用中獎特效算一種，共三種) */
    static EFFECT_TYPES = 3;
    static EFFECT_TYPE = {
        SYMBOL: 0,
        ADD_EFFECT: 1,
        FLY: 2,
    };

    /**@ch 中獎框類型*/
    static ADD_EFFECT_TYPE = {
        WIN_FRAME_NORMAL: 0
    };

    static BIG_NUM = 999999;

    /**@ch 部分表演DELAY時長*/
    static ACTION_DELAY_TIME = {
        TIME_FOR_AWARD_LINE_EFFECT: 1.5,
        FG_FIRST_NEAR_WIN_TIME: 1.1,
        FG_IN_NEAR_WIN_TIME: 0.5
    };

    /**@ch Symbol落下動畫時長 */
    static SYMBOL_FALL_DURATION = 0.1;

    // /**@ch 補牌等消除表演延遲時間 */
    // static ELIMINATE_EFFECT_DELAY_TIME = 0.5;

    /**@ch 等待多久才開始Symbol落下動畫 */
    static SYMBOL_FALL_WAIT_TIME = 0;

    //
    static AWARD_TYPE = {
        AWARD_TYPE_NON: 0x0,  // 沒中獎(0)
        AWARD_TYPE_LINE: 0x1, // 中獎(1)
        AWARD_TYPE_ALL_PLATE: 0x2,// 全盤(2)

        AWARD_TYPE_MAX: 0x7fff
    };
    static SpeedUp = 1;

    static ActualFlyTime = 0.5;
    static WaitTime = 0.75;
    static HitTime = 0.15;

    static SymbolWinName = "Win";

    // static PlateEftOdds = [ 1, 3, 6, 15, 30 ];


    /**@ch BigWin 報獎門檻（單位：贏分金額） */
    static BigWinWinRule = {
        YOU_WIN_MIN: 5,
        BIG_WIN_MIN: 10,
        MEGA_WIN_MIN: 25,
        SUPER_WIN_MIN: 50,
    };

    static SERVER_RET_TYPE = {
        SERVER_SUCCESS: 0, //正常				
        SERVER_ERROR_SEATE: 799, // 錯誤狀態				
        SERVER_NOUSE: 899, // 無用				
        SERVER_MAINTAIN: 998, // 維護中				
        SERVER_SHUTDOWN: 999, // 關機中				
        SERVER_NEED_UID: 1001, //需要UID				
        SERVER_NEED_LOGIN: 1002, //沒有玩家				
        SERVER_TOKEN_ERROR: 1003, //TOKEN 錯誤				
    };
    static LOGIN_RESULT_TYPE = {
        LOGIN_SUCCESS: 0, //登入成功
        LOGIN_FAIL: 1, // 登入失敗
        API_VERIFY_FAIL: 2001,   // TOKEN驗證失敗
        API_LOGIN_REPEAT_FAIL: 2002,    // 重複登入
    };
    static HEART_BEAT_STATE = {
        NOTIFY: 97, //SERVER 通知訊息
        MAINTAIN: 98, //SERVER 維護中
        CLOSE: 99, //SERVER 關閉
    };
    static StringKey = {
        MC_FEATURES_LEFT: "MC_FEATURES_LEFT",
        MC_FEATURES_RIGHT: "MC_FEATURES_RIGHT",
        FREE_GAME_NAME_STRING: "FREE_GAME_NAME_STRING",
    };

    static ShowDisplayValue: ( value: number ) => number = null;

    /**@ch 特色遊玩押注 */
    static FeatureBetValue = 10;

    static OnExit()
    {
        this.BgAudioId = -1;
        this.ShowDisplayValue = null;
    }
}

