import { _decorator, Button, Component, Label, Node, sp, Font } from 'cc';
import { Common } from '../Common/Common';
import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';

const { ccclass, property } = _decorator;

export enum PurseVisualState {
    Idle = 'idle',
    Player = 'player',
    Rival = 'rival',
    Bingo = 'bingo',
}

const PURSE_ANIMATION = {
    REVEAL_WIN: 'RB_BG_CoinExp',
    REVEAL_LOSE: 'RB_BG_SmokeExp',
} as const;

@ccclass('PurseItem')
export class PurseItem extends Component {
    /* 狀態節點 */
    @property({ type: Node }) private idleNode: Node | null = null;
    @property({ type: Node }) private playerNode: Node | null = null;
    @property({ type: Node }) private rivalNode: Node | null = null;
    @property({ type: Node }) private bingoNode: Node | null = null;

    /* 顯示與效果 */
    @property({ type: Label }) private amountLabel: Label | null = null;

    /* 動畫 */
    @property({ type: sp.Skeleton }) private brokenSpine: sp.Skeleton | null = null;
    @property({ type: Button, tooltip: '錢袋的點擊按鈕（可選，不設定則自動取得）' })
    private selectButton: Button | null = null;

    public index = -1;

    private m_currentState: PurseVisualState = PurseVisualState.Idle;
    private m_isRevealWin = false;
    private m_isBreaking = false;
    private m_isSelectable = false;

