271	### 解決方案
272	
273	**替換 `UpdateRivalPreview()` 方法** (第 1866-1950 行)
274	
275	```typescript
276	/**
277	 * @ch 更新 Rival 動畫輪播（按隨機順序切換到下一個錢袋）
278	 */
279	private UpdateRivalPreview(): void {
280	    if (this.m_state !== 'player_select' || !this.m_purseManager) {
281	        return;
282	    }
283	
284	    // 將當前顯示的錢袋恢復為 Idle 狀態
285	    if (this.m_currentRivalPreviewIndex >= 0) {
286	        this.m_purseManager.SetPurseState(this.m_currentRivalPreviewIndex, PurseVisualState.Idle);
287	    }
288	
289	    // 獲取所有未揭示的錢袋索引
290	    const available = this.m_availableIndices.filter(idx =>
291	        !this.m_purseManager?.GetPurse(idx)?.IsRevealed
292	    );
293	
294	    // 如果沒有可用的錢袋，停止輪播
295	    if (available.length === 0) {
296	        this.m_currentRivalPreviewIndex = -1;
297	        this.m_rivalPreviewTimer = 0;
298	        this.m_rivalPreviewQueue = [];
299	        this.m_rivalPreviewQueueIndex = 0;
300	        return;
301	    }
302	
303	    // 如果輪播列表已用完，重新建立
304	    if (this.m_rivalPreviewQueueIndex >= this.m_rivalPreviewQueue.length) {
305	        this.m_rivalPreviewQueue = [...available];
306	        this.ShuffleArray(this.m_rivalPreviewQueue);
307	        this.m_rivalPreviewQueueIndex = 0;
308	    }
309	
310	    // 選擇下一個未揭示的錢袋
311	    let selectedIndex: number | undefined;
312	    const maxScanAttempts = this.m_rivalPreviewQueue.length;
313	    let scanAttempts = 0;
314	
315	    while (scanAttempts < maxScanAttempts && this.m_rivalPreviewQueueIndex < this.m_rivalPreviewQueue.length) {
316	        const candidateIndex = this.m_rivalPreviewQueue[this.m_rivalPreviewQueueIndex];
317	        this.m_rivalPreviewQueueIndex++;
318	        scanAttempts++;
319	
320	        const purse = this.m_purseManager.GetPurse(candidateIndex);
321	        if (purse && !purse.IsRevealed) {
322	            selectedIndex = candidateIndex;
323	            break;
324	        }
325	    }
326	
327	    // 如果沒找到，重新掃描剩餘的可用項
328	    if (selectedIndex === undefined && available.length > 0) {
329	        // 直接從可用列表中取第一個
330	        selectedIndex = available[0];
331	        // 重置隊列
332	        this.m_rivalPreviewQueue = [...available];
333	        this.ShuffleArray(this.m_rivalPreviewQueue);
334	        this.m_rivalPreviewQueueIndex = 1; // 已使用第一個
335	    }
336	
337	    if (selectedIndex !== undefined) {
338	        this.m_currentRivalPreviewIndex = selectedIndex;
339	        // 設置為 Rival 狀態（顯示 Rival 動畫）
340	        this.m_purseManager.SetPurseState(selectedIndex, PurseVisualState.Rival);
341	    } else {
342	        // 如果仍然無法找到，這表示遊戲應該完成
343	        this.m_currentRivalPreviewIndex = -1;
344	        this.m_rivalPreviewTimer = 0;
345	    }
346	
347	    // 設置下一次切換的計時器
348	    this.m_rivalPreviewTimer = this.m_rivalPreviewInterval;
349	}
350	```
