## 解決方案 3️⃣ : 修復對手選擇邏輯中的無限迴圈

### 問題
`UpdateRivalPreview()` 中的輪播選擇邏輯在某些情況下會陷入無效迴圈。

### 當前代碼 (第 1904-1950 行)

```typescript
let selectedIndex: number | undefined;
let maxAttempts = this.m_rivalPreviewQueue.length;
let attempts = 0;

while (attempts < maxAttempts && this.m_rivalPreviewQueueIndex < this.m_rivalPreviewQueue.length) {
    const candidateIndex = this.m_rivalPreviewQueue[this.m_rivalPreviewQueueIndex];
    const purse = this.m_purseManager.GetPurse(candidateIndex);

    if (purse && !purse.IsRevealed) {
        selectedIndex = candidateIndex;
        break;
    }

    this.m_rivalPreviewQueueIndex++;
    attempts++;
}

if (selectedIndex === undefined) {
    // 重新建立列表...
}
```

### 解決方案

**替換 `UpdateRivalPreview()` 方法** (第 1866-1950 行)

```typescript
/**
 * @ch 更新 Rival 動畫輪播（按隨機順序切換到下一個錢袋）
 */
private UpdateRivalPreview(): void {
    if (this.m_state !== 'player_select' || !this.m_purseManager) {
        return;
    }

    // 將當前顯示的錢袋恢復為 Idle 狀態
    if (this.m_currentRivalPreviewIndex >= 0) {
        this.m_purseManager.SetPurseState(this.m_currentRivalPreviewIndex, PurseVisualState.Idle);
    }

    // 獲取所有未揭示的錢袋索引
    const available = this.m_availableIndices.filter(idx =>
        !this.m_purseManager?.GetPurse(idx)?.IsRevealed
    );

    // 如果沒有可用的錢袋，停止輪播
    if (available.length === 0) {
        this.m_currentRivalPreviewIndex = -1;
        this.m_rivalPreviewTimer = 0;
        this.m_rivalPreviewQueue = [];
        this.m_rivalPreviewQueueIndex = 0;
        return;
    }

    // 如果輪播列表已用完，重新建立
    if (this.m_rivalPreviewQueueIndex >= this.m_rivalPreviewQueue.length) {
        this.m_rivalPreviewQueue = [...available];
        this.ShuffleArray(this.m_rivalPreviewQueue);
        this.m_rivalPreviewQueueIndex = 0;
    }

    // 選擇下一個未揭示的錢袋
    let selectedIndex: number | undefined;
    const maxScanAttempts = this.m_rivalPreviewQueue.length;
    let scanAttempts = 0;

    while (scanAttempts < maxScanAttempts && this.m_rivalPreviewQueueIndex < this.m_rivalPreviewQueue.length) {
        const candidateIndex = this.m_rivalPreviewQueue[this.m_rivalPreviewQueueIndex];
        this.m_rivalPreviewQueueIndex++;
        scanAttempts++;

        const purse = this.m_purseManager.GetPurse(candidateIndex);
        if (purse && !purse.IsRevealed) {
            selectedIndex = candidateIndex;
            break;
        }
    }

    // 如果沒找到，重新掃描剩餘的可用項
    if (selectedIndex === undefined && available.length > 0) {
        // 直接從可用列表中取第一個
        selectedIndex = available[0];
        // 重置隊列
        this.m_rivalPreviewQueue = [...available];
        this.ShuffleArray(this.m_rivalPreviewQueue);
        this.m_rivalPreviewQueueIndex = 1; // 已使用第一個
    }

    if (selectedIndex !== undefined) {
        this.m_currentRivalPreviewIndex = selectedIndex;
        // 設置為 Rival 狀態（顯示 Rival 動畫）
        this.m_purseManager.SetPurseState(selectedIndex, PurseVisualState.Rival);
    } else {
        // 如果仍然無法找到，這表示遊戲應該完成
        this.m_currentRivalPreviewIndex = -1;
        this.m_rivalPreviewTimer = 0;
    }

    // 設置下一次切換的計時器
    this.m_rivalPreviewTimer = this.m_rivalPreviewInterval;
}
```

