/**@ch 播放單一符號的Scatter動畫
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 * @param row 行索引 (0 ~ Game_Define.ROW-1)
 * @param isLoop 是否循環播放
 */
private async PlayScatterAnimation(col: number, row: number, isLoop: boolean) : Promise<void> {
    return new Promise<void>(resolve => {
        // 先隱藏符號
        this.SetSymbolShow(col, row, false);

        // 記錄隱藏的位置，便於稍後恢復
        this.m_hiddenScatterPositions.push({col, row});

        const scatterCount = Math.min(this.m_hiddenScatterPositions.length, Game_Define.SCATTER_MAX_COUNT);
        AudioManager.Play(`Scatter0${scatterCount}`);

        let scatterSpine: BaseSpine = null;
        this.m_gameView.EffectPlate.PlayScatterEnterAnimation(col, row, isLoop, (spine: BaseSpine) => {
            scatterSpine = spine;
        }).then(() => {
            // 同步Scatter進入動畫
            if (scatterSpine && this.m_hiddenScatterPositions.length > 1) {
                const position = Common.GetPositionFromColRow(this.m_hiddenScatterPositions[0].col, this.m_hiddenScatterPositions[0].row);
                this.SyncSpineAnimation(scatterSpine, this.m_gameView.EffectPlate.GetScatterEnterAnimationSpine(position));
                log(`SyncSpineAnimation: ${position}`);
            }
            resolve();
        });
    });
}

/**@ch 停止所有 Column 的 Scatter 動畫
 */
private StopAllColumnScattersAnimation() {
    this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();

    // 恢復所有之前隱藏的 Scatter 符號
    for (const pos of this.m_hiddenScatterPositions) {
        this.SetSymbolShow(pos.col, pos.row, true);
    }
    // 清空記錄列表
    this.m_hiddenScatterPositions = [];
}

/**@ch 顯示Scatter預中獎動畫
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 */
private ShowScatterPreWinAnimation(col: number) {
    this.PlayNearWinSound();
    this.m_scatterNearWinColumn = col;
    this.m_gameView.EffectPlate.ShowScatterPreWinAnimation(col);
}

/**@ch 隱藏Scatter預中獎動畫
 * @param col 列索引 (0 ~ Game_Define.COL-1)
 */
private HideScatterPreWinAnimation(col: number) {
    this.StopNearWinSound();
    this.m_scatterNearWinColumn = -1;
    this.m_gameView.EffectPlate.HideScatterPreWinAnimation(col);

