/**
 * @ch 處理最後報獎
 * @param thisRoundWin 本局贏分
 * @param totalWin 總贏分
 * @param accumulatedWin 累積贏分
 * @param isNotShowNormalWin 是否不顯示NormalWin
 */
private async ProcessFinalAward(thisRoundWin: number, totalWin: number, accumulatedWin: number, isNotShowNormalWin: boolean) : Promise<void> {
    log("ProcessFinalAward");

    let isNeedResumeBgm = false;
    const roundWin = this.m_gameView.IsBackToMainGameAndEliminateScatter ? this.m_gameView.SpinAck.TotalWin : thisRoundWin;
    if (this.m_gameView.IsBackToMainGameAndEliminateScatter && this.m_gameView.SpinAck.TotalWin !== this.m_gameView.AccumulatedWin) {
        error("IsBackToMainGameAndEliminateScatter TotalWin !== AccumulatedWin");
    }
    const bet: number = Game_Define.GetNowBetValue();
    const rate = roundWin / bet;
    const thisRoundWinType = Common.GetWinType(rate);

    if (isNotShowNormalWin && thisRoundWinType === WinType.NormalWin) {
       return;
    }


    // 底bar報獎跑分
    newBottombarManager.SetWinValueWithRunningAndCheck(
        {
            maxWin: totalWin,
            finalValue: accumulatedWin,
            duration: this.GetWinEffectRollDuration(thisRoundWinType)
        });

    // 大報獎才可以跳過
    if (thisRoundWinType >= WinType.BigWin) {
        // 暫停背景音樂
        isNeedResumeBgm = true;
        this.PauseBgm();

        // 秀大贏分
        newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );

        // 表演報獎動畫（NormalWin 不需要額外報獎）
        await this.PlayWinEffect(roundWin, thisRoundWinType, () => {
        }, () => {
            //newBottombarManager.SetWinValue(accumulatedWin);
            newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: accumulatedWin } );
        });
    }
    else {
        // NormalWin：不額外報獎，只需要更新底Bar贏分
        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: accumulatedWin } );
    }

    // 恢復背景音樂
    if (isNeedResumeBgm) {
        this.ResumeBgm();
    }
}

