    if (!this.m_gameView.IsBonusGame) {
        let thisRoundWin: number = this.m_gameView.RoundInfo.RoundWin;
        let bet: number = Game_Define.GetNowBetValue();
        const rate = thisRoundWin / bet;
        const plateQueue = this.m_gameView.RoundInfo.PlateQueue;
        const spinAck = this.m_gameView.SpinAck;
        const totalWin = spinAck.TotalWin;

        /**@ch 設定盤面符號不暗 */
        this.m_gameView.SlotReels.SetSymbolDark( false, -1 );

        /**@ch 是否需要獲取累積贏分 */
        const isNeedGetAccumulatedWin = spinAck && spinAck.RoundQueue.length > 0;

        /**@ch 累積贏分 */
        let accumulatedWin = isNeedGetAccumulatedWin ? this.m_gameView.AccumulatedWin : 0;

        /**@ch 是否不表演Scatter中獎動畫 */
        let isNotPlayScatterBingoAnimation = this.m_gameView.IsBackToMainGameAndEliminateScatter;

        if (this.m_gameView.IsFreeGame) {
            // 重置免費遊戲進度
            this.ResetFreeGameProgress(true);
        }

        let isFinalPlateInfo = false;
        for (let i = 0; i < plateQueue.length; i++) {
            this.m_currentPlateInfo = plateQueue[i];
            this.m_gameView.CurComboPlateIndex = i;
            isFinalPlateInfo = i === plateQueue.length - 1;

            // 表演GoldenArrow和Scatter特殊效果
            await this.ProcessGoldenArrowAndScatterEffects(isNotPlayScatterBingoAnimation);

            // 判斷是否需要報獎
            if (this.m_currentPlateInfo.AwardDataVec.length > 0 && this.m_currentPlateInfo.Win > 0) {
                // 計算累積贏分
                accumulatedWin += this.m_currentPlateInfo.Win;

                await this.ProcessSmallAward(totalWin, accumulatedWin);
            }

            // 判斷是否需要消除
            if (this.m_currentPlateInfo.EliminatePos.length > 0 && !isFinalPlateInfo) {
                await this.ProcessEliminateEffect();
            }
        }

        // 累積贏分
        if (isNeedGetAccumulatedWin) {
            this.m_gameView.AccumulatedWin = accumulatedWin;
        }

        // 若是主遊戲且有MaxFlag，則跳MaxFlag MessageBox
        if (isMaxFlag && Define.IsInMG()) {
            await this.PlayMaxFlagMessageBox();
        }

        // 最後報獎 原版FreeGame or BonusGame不報大獎的機制
        if (
            (rate > 0 && !this.m_gameView.IsGoingToBonus && !this.m_gameView.IsGoingToFree && !this.m_gameView.IsFreeGame)
            || this.m_gameView.IsBackToMainGameAndEliminateScatter
        ) {
            const isNotShowNormalWin = Define.IsInMG() && !this.m_gameView.IsBackToMainGameAndEliminateScatter;
            await this.ProcessFinalAward(thisRoundWin, totalWin, accumulatedWin, isNotShowNormalWin);
        }

        if (this.m_gameView.IsFreeGame) {
            // 重置免費遊戲進度
            this.ResetFreeGameProgress(true);
        }
    }

    // 特殊遊戲要等AwardState表演結束後才跳MaxFlag MessageBox
    if (this.m_gameView.IsBonusGame || this.m_gameView.IsFreeGame) {
        if (isMaxFlag) {
            await this.PlayMaxFlagMessageBox();
        }
    }

    this.m_isShowAwardEffectEnd = true;
}

public OnProcess()
{
    if (this.IsProcessEnd()) {
        if (this.m_gameView.IsBackToMainGameAndEliminateScatter) {
            this.m_gameView.IsBackToMainGameAndEliminateScatter = false;
        }
        this.m_gameView.AfterShowWin();
    }
}

public OnLeave()
{
    this.m_currentPlateInfo = null;
    this.m_gameView.EffectPlate.ReturnAllSymbolChangeEffectNodes();
}

/**
 * @ch 是否處理結束
 */
private IsProcessEnd(): boolean
{
    return this.m_isShowAwardEffectEnd;
}

/**
 * @ch 處理 GoldenArrow 和 Scatter 特殊效果
 * @param isNotPlayScatterBingoAnimation 是否不播放 Scatter 動畫
 */
private async ProcessGoldenArrowAndScatterEffects(isNotPlayScatterBingoAnimation: boolean): Promise<void> {
    // 表演GoldenArrow中獎動畫
    const isPlayGoldenArrow = this.IsPlayGoldenArrow();
    if (isPlayGoldenArrow) {
        await this.PlayGoldenArrow();
    }

    // 表演Scatter中獎動畫
    if (this.IsPlayScatterBingo() && !isNotPlayScatterBingoAnimation) {
        await this.PlayScatterBingo();
    }

    // 判斷是否要表演GoldenArrow退場動畫
    if (isPlayGoldenArrow) {
        this.PlayGoldenArrowExitAnimation();
    }
}

/**
 * @ch 處理小報獎
 * @param totalWin 總贏分
 * @param accumulatedWin 累積贏分
 */
private async ProcessSmallAward(totalWin: number, accumulatedWin: number) : Promise<void> {
    log("ProcessSmallAward");

    let promises: Promise<void>[] = [];

    // 底bar報獎跑分
    newBottombarManager.SetWinValueWithRunningAndCheck(
        {
            maxWin: totalWin,
            finalValue: accumulatedWin,
            duration: this.GetWinEffectRollDuration(WinType.NormalWin)
        });

    // 呼叫小報獎效果
    promises.push(this.PlayWinEffect(this.m_currentPlateInfo.Win, WinType.NormalWin));
